## 2. `pcapng_stubs.c` – C / C++ implementation

> **Important** – this file *must* be compiled as C++ (`g++`/`clang++`) because it talks to the C++ libpcapng API.  The file is written with `extern "C"` wrappers so that the OCaml runtime can find the symbols.

```c
/* ----------------------------------------------------------------------
   pcapng_stubs.c  –  OCaml bindings for libpcapng
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE          /* avoid name clashes */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/bigarray.h>
#include <caml/fail.h>

#include <cstddef>
#include <cstdint>
#include <cstring>
#include <string>
#include <exception>

/* -------------------------------------------------------------
   Replace the following includes / forward declarations with the
   real libpcapng headers you are using.
   ------------------------------------------------------------- */
#include "libpcapng.hpp"          /* <-- your libpcapng header */

/* -------------------------------------------------------------
   OCaml representation of a libpcapng file handle.
   ------------------------------------------------------------- */
typedef struct {
    pcapng::Reader *reader;          /* the C++ object that owns the file */
} ocaml_pcapng_handle;

/* -------------------------------------------------------------
   OCaml representation of a *single* frame.
   The same OCaml value is reused for each iteration step.
   ------------------------------------------------------------- */
typedef struct {
    const uint8_t *data;   /* pointer into libpcapng's internal buffer */
    size_t         len;    /* length of the packet */
    double         ts;     /* timestamp (seconds since epoch) */
} ocaml_frame;

/* -------------------------------------------------------------
   Custom operations for the `frame` type.
   No finaliser is needed – the data pointer points into memory that
   stays valid as long as the file is open.
   ------------------------------------------------------------- */
static void frame_finalize(value v) {
    /* No heap allocation inside the custom block, nothing to free. */
    (void)v;
}

static struct custom_operations frame_ops = {
    "pcapng.frame",
    frame_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* -------------------------------------------------------------
   Helper: allocate a fresh OCaml custom block that will hold an
   `ocaml_frame`.  The block is allocated once and then recycled.
   ------------------------------------------------------------- */
static value caml_alloc_frame(void) {
    return caml_alloc_custom(&frame_ops,
                             sizeof(ocaml_frame),
                             0,   /* mem size (no extra heap) */
                             1);  /* max depth */
}

/* -------------------------------------------------------------
   OCaml → C: open a file
   ------------------------------------------------------------- */
CAMLprim value caml_pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_handle);

    const char *c_path = String_val(v_path);
    ocaml_pcapng_handle *h = nullptr;

    try {
        h = caml_stat_alloc(sizeof(*h));
        h->reader = new pcapng::Reader(std::string(c_path));
    } catch (const std::exception &e) {
        caml_stat_free(h);
        caml_failwith(e.what());
    }

    v_handle = caml_alloc_small(1, Abstract_tag);
    Field(v_handle, 0) = (value)h;   /* store the pointer as abstract value */
    CAMLreturn(v_handle);
}

/* -------------------------------------------------------------
   OCaml → C: close the file and free resources
   ------------------------------------------------------------- */
CAMLprim value caml_pcapng_close(value v_handle) {
    CAMLparam1(v_handle);
    ocaml_pcapng_handle *h = (ocaml_pcapng_handle *)Field(v_handle, 0);
    if (h) {
        delete h->reader;
        caml_stat_free(h);
        Field(v_handle, 0) = 0;
    }
    CAMLreturn(Val_unit);
}

/* -------------------------------------------------------------
   The hot loop: iterate over all frames and call the OCaml callback.
   The callback receives a *single* `frame` value that is mutated on
   each iteration.  This avoids allocating a fresh OCaml value per
   frame.
   ------------------------------------------------------------- */
CAMLprim value caml_pcapng_iter(value v_handle, value v_cb) {
    CAMLparam2(v_handle, v_cb);
    CAMLlocal1(v_frame);          /* the mutable frame value */

    ocaml_pcapng_handle *h = (ocaml_pcapng_handle *)Field(v_handle, 0);
    if (!h || !h->reader) caml_failwith("pcapng: file not opened");

    /* Allocate the mutable frame once. */
    v_frame = caml_alloc_frame();
    ocaml_frame *f = (ocaml_frame *)Data_custom_val(v_frame);

    try {
        /* The actual iterator type depends on libpcapng; replace the
           following with the real iterator you get from the library. */
        pcapng::Iterator it = h->reader->begin();
        pcapng::Iterator end = h->reader->end();

        for ( ; it != end; ++it ) {
            const pcapng::Packet &pkt = *it;   /* one packet from libpcapng */

            /* Fill the custom block – no allocation, just pointer writes */
            f->data = pkt.payload();            /* const uint8_t* */
            f->len  = pkt.payload_len();        /* size_t */
            f->ts   = pkt.timestamp();          /* double (seconds) */

            /* Call the OCaml callback.  If the callback raises, the
               exception propagates out of this function and aborts the
               iteration. */
            caml_callback_exn(v_cb, v_frame);
            if (Is_exception_result(v_frame)) {
                /* Propagate the exception to the caller. */
                caml_raise(Extract_exception(v_frame));
            }
        }
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    }

    CAMLreturn(Val_unit);
}

/* -------------------------------------------------------------
   Accessors for the `frame` value.
   ------------------------------------------------------------- */
CAMLprim value caml_pcapng_frame_len(value v_frame) {
    CAMLparam1(v_frame);
    ocaml_frame *f = (ocaml_frame *)Data_custom_val(v_frame);
    CAMLreturn(Val_int((int)f->len));
}

CAMLprim value caml_pcapng_frame_timestamp(value v_frame) {
    CAMLparam1(v_frame);
    ocaml_frame *f = (ocaml_frame *)Data_custom_val(v_frame);
    CAMLreturn(caml_copy_double(f->ts));
}

/* Return a *copy* of the raw bytes inside a fresh OCaml Bytes.t.
   This copy is unavoidable if the user wants a mutable OCaml string.
   If you need zero‑copy you can expose a Bigarray view instead. */
CAMLprim value caml_pcapng_frame_data(value v_frame) {
    CAMLparam1(v_frame);
    CAMLlocal1(v_bytes);

    ocaml_frame *f = (ocaml_frame *)Data_custom_val(v_frame);
    v_bytes = caml_alloc_initialized_string((mlsize_t)f->len, '\0');

    if (f->len > 0) {
        memcpy(String_val(v_bytes), f->data, f->len);
    }

    CAMLreturn(v_bytes);
}

/* -------------------------------------------------------------
   Register the entry points for the OCaml side.  (Optional: you can
   also use the `external` declarations directly without registration.)
   ------------------------------------------------------------- */
static struct caml_named_value caml_named_values[] = {
    { "pcapng_open_file", caml_pcapng_open_file },
    { "pcapng_close",     caml_pcapng_close },
    { "pcapng_iter",      caml_pcapng_iter },
    { "pcapng_frame_len", caml_pcapng_frame_len },
    { "pcapng_frame_timestamp", caml_pcapng_frame_timestamp },
    { "pcapng_frame_data", caml_pcapng_frame_data },
    { NULL, NULL }
};

CAMLprim value caml_register_pcapng_stubs(value unit) {
    CAMLparam1(unit);
    caml_register_named_values(caml_named_values);
    CAMLreturn(Val_unit);
}
```

